const GetAccount = {"response":{"200":{"title":"Account","type":"object","description":"The account API serves important information related to an account, including account status, funds available for trade, funds available for withdrawal, and various flags relevant to an account’s ability to trade. An account maybe be blocked for just for trades (trades_blocked flag) or for both trades and transfers (account_blocked flag) if Alpaca identifies the account to engaging in any suspicious activity. Also, in accordance with FINRA’s pattern day trading rule, an account may be flagged for pattern day trading (pattern_day_trader flag), which would inhibit an account from placing any further day-trades. Please note that cryptocurrencies are not eligible assets to be used as collateral for margin accounts and will require the asset be traded using cash only.\n","x-examples":{"example-1":{"account_blocked":false,"account_number":"010203ABCD","buying_power":"262113.632","cash":"-23140.2","created_at":"2019-06-12T22:47:07.99658Z","currency":"USD","daytrade_count":0,"balance_asof":"2023-09-27","daytrading_buying_power":"262113.632","equity":"103820.56","id":"e6fe16f3-64a4-4921-8928-cadf02f92f98","initial_margin":"63480.38","last_equity":"103529.24","last_maintenance_margin":"38000.832","long_market_value":"126960.76","maintenance_margin":"38088.228","multiplier":"4","pattern_day_trader":false,"portfolio_value":"103820.56","regt_buying_power":"80680.36","options_buying_power":"40340.18","short_market_value":"0","shorting_enabled":true,"sma":"0","status":"ACTIVE","trade_suspended_by_user":false,"trading_blocked":false,"transfers_blocked":false,"options_approved_level":2,"options_trading_level":1,"intraday_adjustments":"0","pending_reg_taf_fees":"0"}},"properties":{"id":{"type":"string","description":"Account Id.\n","format":"uuid"},"account_number":{"type":"string","description":"Account number."},"status":{"type":"string","title":"AccountStatus","enum":["ONBOARDING","SUBMISSION_FAILED","SUBMITTED","ACCOUNT_UPDATED","APPROVAL_PENDING","ACTIVE","REJECTED"],"description":"An enum representing the various possible account status values.\n\nMost likely, the account status is ACTIVE unless there is any problem. The account status may get in ACCOUNT_UPDATED when personal information is being updated from the dashboard, in which case you may not be allowed trading for a short period of time until the change is approved.\n\n- ONBOARDING\n  The account is onboarding.\n- SUBMISSION_FAILED\n  The account application submission failed for some reason.\n- SUBMITTED\n  The account application has been submitted for review.\n- ACCOUNT_UPDATED\n  The account information is being updated.\n- APPROVAL_PENDING\n  The final account approval is pending.\n- ACTIVE\n  The account is active for trading.\n- REJECTED\n  The account application has been rejected.\n\n`ONBOARDING` `SUBMISSION_FAILED` `SUBMITTED` `ACCOUNT_UPDATED` `APPROVAL_PENDING` `ACTIVE` `REJECTED`","x-examples":{"example-1":"ACTIVE"},"examples":["ACTIVE"]},"currency":{"type":"string","description":"USD\n","examples":["USD"]},"cash":{"description":"Cash Balance\n","type":"string"},"portfolio_value":{"description":"Total value of cash + holding positions (This field is deprecated. It is equivalent to the equity field.)","type":"string"},"non_marginable_buying_power":{"description":"Current available non-margin dollar buying power","type":"string","x-stoplight":{"id":"z0ydzt6yqegll"}},"accrued_fees":{"description":"The fees collected.","type":"string","x-stoplight":{"id":"b1gospbwoz961"}},"pending_transfer_in":{"description":"Cash pending transfer in.","type":"string","x-stoplight":{"id":"83ckvzqu3jewp"}},"pending_transfer_out":{"description":"Cash pending transfer out.","type":"string","x-stoplight":{"id":"gkxijaueofvdg"}},"pattern_day_trader":{"type":"boolean","description":"Whether or not the account has been flagged as a pattern day trader"},"trade_suspended_by_user":{"type":"boolean","description":"User setting. If true, the account is not allowed to place orders."},"trading_blocked":{"type":"boolean","description":"If true, the account is not allowed to place orders.\n"},"transfers_blocked":{"type":"boolean","description":"If true, the account is not allowed to request money transfers."},"account_blocked":{"type":"boolean","description":"If true, the account activity by user is prohibited."},"created_at":{"type":"string","description":"Timestamp this account was created at\n","format":"date-time"},"shorting_enabled":{"type":"boolean","description":"Flag to denote whether or not the account is permitted to short"},"long_market_value":{"description":"Real-time MtM value of all long positions held in the account\n","type":"string"},"short_market_value":{"description":"Real-time MtM value of all short positions held in the account","type":"string"},"equity":{"description":"Cash + long_market_value + short_market_value","type":"string"},"last_equity":{"description":"Equity as of previous trading day at 16:00:00 ET","type":"string"},"multiplier":{"description":"Buying power multiplier that represents account margin classification; valid values 1 (standard limited margin account with 1x buying power), 2 (reg T margin account with 2x intraday and overnight buying power; this is the default for all non-PDT accounts with $2,000 or more equity), 4 (PDT account with 4x intraday buying power and 2x reg T overnight buying power)","type":"string"},"buying_power":{"description":"Current available $ buying power; If multiplier = 4, this is your daytrade buying power which is calculated as (last_equity - (last) maintenance_margin) * 4; If multiplier = 2, buying_power = max(equity – initial_margin,0) * 2; If multiplier = 1, buying_power = cash","type":"string"},"initial_margin":{"description":"Reg T initial margin requirement (continuously updated value)","type":"string"},"maintenance_margin":{"description":"Maintenance margin requirement (continuously updated value)","type":"string"},"sma":{"type":"string","description":"Value of special memorandum account (will be used at a later date to provide additional buying_power)"},"daytrade_count":{"type":"integer","description":"The current number of daytrades that have been made in the last 5 trading days (inclusive of today)"},"balance_asof":{"type":"string","description":"The date of the snapshot for `last_*` fields","examples":["2021-04-01"]},"last_maintenance_margin":{"description":"Your maintenance margin requirement on the previous trading day","type":"string"},"daytrading_buying_power":{"description":"Your buying power for day trades (continuously updated value)","type":"string"},"regt_buying_power":{"description":"Your buying power under Regulation T (your excess equity - equity minus margin value - times your margin multiplier)\n","type":"string"},"options_buying_power":{"description":"Your buying power for options trading\n","type":"string"},"options_approved_level":{"type":"integer","description":"The options trading level that was approved for this account.\n0=disabled, 1=Covered Call/Cash-Secured Put, 2=Long Call/Put, 3=Spreads/Straddles.\n\n\n`1` `2` `3`","enum":[0,1,2,3],"examples":[3]},"options_trading_level":{"type":"integer","description":"The effective options trading level of the account.\nThis is the minimum between account options_approved_level and account configurations max_options_trading_level.\n0=disabled, 1=Covered Call/Cash-Secured Put, 2=Long Call/Put, 3=Spreads/Straddles.\n\n\n`1` `2` `3`","enum":[0,1,2,3],"examples":[3]},"intraday_adjustments":{"type":"string","description":"The intraday adjustment by non_trade_activities such as fund deposit/withdraw.\n","examples":["0"]},"pending_reg_taf_fees":{"type":"string","description":"Pending regulatory fees for the account.\n"}},"required":["id","status"],"$schema":"http://json-schema.org/draft-04/schema#"}}} as const
