const GetOptionContractSymbolOrId = {"metadata":{"allOf":[{"type":"object","properties":{"symbol_or_id":{"type":"string","$schema":"http://json-schema.org/draft-04/schema#","description":"symbol or contract ID"}},"required":["symbol_or_id"]}]},"response":{"200":{"type":"object","properties":{"id":{"type":"string","description":"The unique identifier of the option contract.","examples":["98359ef7-5124-49f3-85ea-5cf02df6defa"]},"symbol":{"type":"string","description":"The symbol representing the option contract.","examples":["AAPL250620C00100000"]},"name":{"type":"string","description":"The name of the option contract.","examples":["AAPL Jun 20 2025 100 Call"]},"status":{"type":"string","description":"The status of the option contract.\n\n`active` `inactive`","enum":["active","inactive"],"examples":["active"]},"tradable":{"type":"boolean","description":"Indicates whether the option contract is tradable.","examples":[true]},"expiration_date":{"type":"string","format":"date","description":"The expiration date of the option contract.","examples":["2025-06-20"]},"root_symbol":{"type":"string","description":"The root symbol of the option contract.","examples":["AAPL"]},"underlying_symbol":{"type":"string","description":"The underlying symbol of the option contract.","examples":["AAPL"]},"underlying_asset_id":{"type":"string","description":"The unique identifier of the underlying asset.","examples":["b0b6dd9d-8b9b-48a9-ba46-b9d54906e415"]},"type":{"type":"string","description":"The type of the option contract.\n\n`call` `put`","enum":["call","put"],"examples":["call"]},"style":{"type":"string","description":"The style of the option contract.\n\n`american` `european`","enum":["american","european"],"examples":["american"]},"strike_price":{"type":"string","description":"The strike price of the option contract.","examples":["100"]},"multiplier":{"type":"string","description":"The multiplier of the option contract is crucial for calculating both the trade premium and the extended strike price. In standard contracts, the multiplier is always set to 100.\nFor instance, if a contract is traded at $1.50 and the multiplier is 100, the total amount debited when buying the contract would be $150.00.\nSimilarly, when exercising a call contract, the total cost will be equal to the strike price times the multiplier.","examples":["100"]},"size":{"type":"string","description":"Represents the number of underlying shares to be delivered in case the contract is exercised/assigned. For standard contracts, this is always 100.\nThis field should **not** be used as a multiplier, specially for non-standard contracts.","examples":["100"]},"open_interest":{"type":"string","description":"The open interest of the option contract.","examples":["237"]},"open_interest_date":{"type":"string","format":"date","description":"The date of the open interest data.","examples":["2023-12-11"]},"close_price":{"type":"string","description":"The close price of the option contract.","examples":["148.38"]},"close_price_date":{"type":"string","format":"date","description":"The date of the close price data.","examples":["2023-12-11"]},"deliverables":{"type":"array","description":"Represents the deliverables tied to the option contract. While standard contracts entail a single deliverable, non-standard ones can encompass multiple deliverables, each potentially customized with distinct parameters.\nThis array is included in the list contracts response only if the query parameter show_deliverables=true is provided.\n","items":{"type":"object","properties":{"type":{"type":"string","description":"Type of deliverable, indicating whether it's cash or equity. For standard contracts, it is always \"equity\".\n\n\n`cash` `equity`","enum":["cash","equity"],"examples":["equity"]},"symbol":{"type":"string","description":"Symbol of the deliverable. For standard contracts, this is equivalent to the underlying symbol of the contract.\n","examples":["AAPL"]},"asset_id":{"type":"string","description":"Unique identifier of the deliverable asset. For standard contracts, this is equivalent to underlying_asset_id of the contracts.\nThis field is not returned for cash deliverables.\n","examples":["b0b6dd9d-8b9b-48a9-ba46-b9d54906e415"]},"amount":{"type":"string","description":"The deliverable amount. For cash deliverables, this is the cash amount.\nFor standard contract, this is always 100.\nThis field can be null in case the deliverable settlement is delayed and the amount is yet to be determined.\n","examples":["100"]},"allocation_percentage":{"type":"string","description":"Cost allocation percentage of the deliverable.\nThis is used to determine the cost basis of the equity shares received from the exercise, specially for non-standard contracts with multiple deliverables.\n","examples":["100"]},"settlement_type":{"type":"string","description":"Indicates when the deliverable will be settled if the contract is exercised/assigned.\n\n\n`T+0` `T+1` `T+2` `T+3` `T+4` `T+5`","enum":["T+0","T+1","T+2","T+3","T+4","T+5"],"examples":["T+2"]},"settlement_method":{"type":"string","description":"Indicates the settlement method that will be used:\n- **BTOB**: Broker to Broker\n- **CADF**: Cash Difference\n- **CAFX**: Cash Fixed\n- **CCC**: Correspondent Clearing Corp\n\n\n`BTOB` `CADF` `CAFX` `CCC`","enum":["BTOB","CADF","CAFX","CCC"],"examples":["CCC"]},"delayed_settlement":{"type":"boolean","description":"If true, the settlement of the deliverable will be delayed.\nFor instance, in the event of a contract with a delayed deliverable being exercised, both the availability of the deliverable and its settlement may be postponed beyond the typical timeframe.\n","examples":[false]}},"required":["type","symbol","amount","allocation_percentage","settlement_type","settlement_method","delayed_settlement"]}}},"required":["id","symbol","name","status","tradable","expiration_date","underlying_symbol","underlying_asset_id","type","style","strike_price","multiplier","size"],"$schema":"http://json-schema.org/draft-04/schema#"},"404":{"title":"Error","type":"object","properties":{"code":{"type":"number"},"message":{"type":"string"}},"required":["code","message"],"$schema":"http://json-schema.org/draft-04/schema#"}}} as const
