const GetOrderByClientOrderId = {"metadata":{"allOf":[{"type":"object","properties":{"client_order_id":{"type":"string","$schema":"http://json-schema.org/draft-04/schema#","description":"The client-assigned order ID."}},"required":["client_order_id"]}]},"response":{"200":{"description":"The Orders API allows a user to monitor, place and cancel their orders with Alpaca.\n\nEach order has a unique identifier provided by the client. This client-side unique order ID will be automatically generated by the system if not provided by the client, and will be returned as part of the order object along with the rest of the fields described below. Once an order is placed, it can be queried using the client-side order ID to check the status.\n\nUpdates on open orders at Alpaca will also be sent over the streaming interface, which is the recommended method of maintaining order state.","type":"object","title":"Order","properties":{"id":{"type":"string","description":"Order ID"},"client_order_id":{"type":"string","description":"Client unique order ID","maxLength":128},"created_at":{"type":"string","format":"date-time"},"updated_at":{"type":"string","format":"date-time"},"submitted_at":{"type":"string","format":"date-time"},"filled_at":{"type":"string","format":"date-time"},"expired_at":{"type":"string","format":"date-time"},"canceled_at":{"type":"string","format":"date-time"},"failed_at":{"type":"string","format":"date-time"},"replaced_at":{"type":"string","format":"date-time"},"replaced_by":{"type":"string","format":"uuid","description":"The order ID that this order was replaced by"},"replaces":{"type":"string","format":"uuid","description":"The order ID that this order replaces"},"asset_id":{"type":"string","format":"uuid","description":"Asset ID (For options this represents the option contract ID)"},"symbol":{"type":"string","minLength":1,"description":"Asset symbol, required for all order classes except for `mleg`"},"asset_class":{"type":"string","title":"AssetClass","enum":["us_equity","us_option","crypto"],"description":"This represents the category to which the asset belongs to. It serves to identify the nature of the financial instrument, with options including \"us_equity\" for U.S. equities, \"us_option\" for U.S. options, and \"crypto\" for cryptocurrencies.\n\n`us_equity` `us_option` `crypto`","x-examples":{"example-1":"us_equity"},"examples":["us_equity"]},"notional":{"type":"string","minLength":1,"description":"Ordered notional amount. If entered, qty will be null. Can take up to 9 decimal points."},"qty":{"type":"string","minLength":1,"description":"Ordered quantity. If entered, notional will be null. Can take up to 9 decimal points. Required if order class is `mleg`."},"filled_qty":{"type":"string","minLength":1,"description":"Filled quantity"},"filled_avg_price":{"type":"string","description":"Filled average price"},"order_class":{"type":"string","enum":["simple","bracket","oco","oto","mleg",""],"description":"The order classes supported by Alpaca vary based on the order's security type. The following provides a comprehensive breakdown of the supported order classes for each category:\n  - Equity trading: simple (or \"\"), oco, oto, bracket.\n  - Options trading:\n    - simple (or \"\")\n    - mleg (required for multi-leg complex option strategies)\n  - Crypto trading: simple (or \"\").\n\n`simple` `bracket` `oco` `oto` `mleg`","title":"OrderClass","examples":["bracket"]},"order_type":{"type":"string","deprecated":true,"description":"Deprecated in favour of the field \"type\" "},"type":{"type":"string","enum":["market","limit","stop","stop_limit","trailing_stop"],"description":"The order types supported by Alpaca vary based on the order's security type. The following provides a comprehensive breakdown of the supported order types for each category:\n - Equity trading: market, limit, stop, stop_limit, trailing_stop.\n - Options trading: market, limit.\n - Multileg Options trading: market, limit.\n - Crypto trading: market, limit, stop_limit.\n\n`market` `limit` `stop` `stop_limit` `trailing_stop`","title":"OrderType","examples":["market"]},"side":{"type":"string","enum":["buy","sell"],"title":"OrderSide","description":"Represents which side this order was on:\n- buy\n- sell\nRequired for all order classes except for mleg.\n\n`buy` `sell`","examples":["buy"]},"time_in_force":{"type":"string","title":"TimeInForce","description":"The Time-In-Force values supported by Alpaca vary based on the order's security type. Here is a breakdown of the supported TIFs for each specific security type:\n- Equity trading: day, gtc, opg, cls, ioc, fok.\n- Options trading: day.\n- Crypto trading: gtc, ioc.\n\nBelow are the descriptions of each TIF:\n- day:\n  A day order is eligible for execution only on the day it is live. By default, the order is only valid during Regular Trading Hours (9:30am - 4:00pm ET). If unfilled after the closing auction, it is automatically canceled. If submitted after the close, it is queued and submitted the following trading day. However, if marked as eligible for extended hours, the order can also execute during supported extended hours.\n\n- gtc:\n  The order is good until canceled. Non-marketable GTC limit orders are subject to price adjustments to offset corporate actions affecting the issue. We do not currently support Do Not Reduce (DNR) orders to opt out of such price adjustments.\n\n- opg:\n  Use this TIF with a market/limit order type to submit “market on open” (MOO) and “limit on open” (LOO) orders. This order is eligible to execute only in the market opening auction. Any unfilled orders after the open will be cancelled. OPG orders submitted after 9:28am but before 7:00pm ET will be rejected. OPG orders submitted after 7:00pm will be queued and routed to the following day’s opening auction. On open/on close orders are routed to the primary exchange. Such orders do not necessarily execute exactly at 9:30am / 4:00pm ET but execute per the exchange’s auction rules.\n\n- cls:\n  Use this TIF with a market/limit order type to submit “market on close” (MOC) and “limit on close” (LOC) orders. This order is eligible to execute only in the market closing auction. Any unfilled orders after the close will be cancelled. CLS orders submitted after 3:50pm but before 7:00pm ET will be rejected. CLS orders submitted after 7:00pm will be queued and routed to the following day’s closing auction. Only available with API v2.\n\n- ioc:\n  An Immediate Or Cancel (IOC) order requires all or part of the order to be executed immediately. Any unfilled portion of the order is canceled. Only available with API v2. Most market makers who receive IOC orders will attempt to fill the order on a principal basis only, and cancel any unfilled balance. On occasion, this can result in the entire order being cancelled if the market maker does not have any existing inventory of the security in question.\n\n- fok:\n  A Fill or Kill (FOK) order is only executed if the entire order quantity can be filled, otherwise the order is canceled. Only available with API v2.\n\n`day` `gtc` `opg` `cls` `ioc` `fok`","enum":["day","gtc","opg","cls","ioc","fok"],"examples":["day"]},"limit_price":{"type":"string","description":"Limit price"},"stop_price":{"description":"Stop price","type":"string"},"status":{"type":"string","title":"OrderStatus","description":"An order executed through Alpaca can experience several status changes during its lifecycle. The most common statuses are described in detail below:\n\n- new\n  The order has been received by Alpaca, and routed to exchanges for execution. This is the usual initial state of an order.\n\n- partially_filled\n  The order has been partially filled.\n\n- filled\n  The order has been filled, and no further updates will occur for the order.\n\n- done_for_day\n  The order is done executing for the day, and will not receive further updates until the next trading day.\n\n- canceled\n  The order has been canceled, and no further updates will occur for the order. This can be either due to a cancel request by the user, or the order has been canceled by the exchanges due to its time-in-force.\n\n- expired\n  The order has expired, and no further updates will occur for the order.\n\n- replaced\n  The order was replaced by another order, or was updated due to a market event such as corporate action.\n\n- pending_cancel\n  The order is waiting to be canceled.\n\n- pending_replace\n  The order is waiting to be replaced by another order. The order will reject cancel request while in this state.\n\nLess common states are described below. Note that these states only occur on very rare occasions, and most users will likely never see their orders reach these states:\n\n- accepted\n  The order has been received by Alpaca, but hasn’t yet been routed to the execution venue. This could be seen often out side of trading session hours.\n\n- pending_new\n  The order has been received by Alpaca, and routed to the exchanges, but has not yet been accepted for execution. This state only occurs on rare occasions.\n\n- accepted_for_bidding\n  The order has been received by exchanges, and is evaluated for pricing. This state only occurs on rare occasions.\n\n- stopped\n  The order has been stopped, and a trade is guaranteed for the order, usually at a stated price or better, but has not yet occurred. This state only occurs on rare occasions.\n\n- rejected\n  The order has been rejected, and no further updates will occur for the order. This state occurs on rare occasions and may occur based on various conditions decided by the exchanges.\n\n- suspended\n  The order has been suspended, and is not eligible for trading. This state only occurs on rare occasions.\n\n- calculated\n  The order has been completed for the day (either filled or done for day), but remaining settlement calculations are still pending. This state only occurs on rare occasions.\n\n\nAn order may be canceled through the API up until the point it reaches a state of either filled, canceled, or expired.\n\n`new` `partially_filled` `filled` `done_for_day` `canceled` `expired` `replaced` `pending_cancel` `pending_replace` `accepted` `pending_new` `accepted_for_bidding` `stopped` `rejected` `suspended` `calculated`","enum":["new","partially_filled","filled","done_for_day","canceled","expired","replaced","pending_cancel","pending_replace","accepted","pending_new","accepted_for_bidding","stopped","rejected","suspended","calculated"],"examples":["new"]},"extended_hours":{"type":"boolean","description":"If true, eligible for execution outside regular trading hours."},"legs":{"type":"array","description":"When querying non-simple order_class orders in a nested style, an array of Order entities associated with this order. Otherwise, null. Required if order class is `mleg`.","items":{"description":"This is copy of Order response schemas as a workaround of displaying issue of nested Order recursively for legs","type":"object","title":"Order","properties":{"id":{"type":"string","description":"Order ID"},"client_order_id":{"type":"string","description":"Client unique order ID","maxLength":128},"created_at":{"type":"string","format":"date-time"},"updated_at":{"type":"string","format":"date-time"},"submitted_at":{"type":"string","format":"date-time"},"filled_at":{"type":"string","format":"date-time"},"expired_at":{"type":"string","format":"date-time"},"canceled_at":{"type":"string","format":"date-time"},"failed_at":{"type":"string","format":"date-time"},"replaced_at":{"type":"string","format":"date-time"},"replaced_by":{"type":"string","format":"uuid","description":"The order ID that this order was replaced by"},"replaces":{"type":"string","format":"uuid","description":"The order ID that this order replaces"},"asset_id":{"type":"string","format":"uuid","description":"Asset ID (For options this represents the option contract ID)"},"symbol":{"type":"string","minLength":1,"description":"Asset symbol"},"asset_class":{"type":"string","title":"AssetClass","enum":["us_equity","us_option","crypto"],"description":"This represents the category to which the asset belongs to. It serves to identify the nature of the financial instrument, with options including \"us_equity\" for U.S. equities, \"us_option\" for U.S. options, and \"crypto\" for cryptocurrencies.\n\n`us_equity` `us_option` `crypto`","x-examples":{"example-1":"us_equity"},"examples":["us_equity"]},"notional":{"type":"string","minLength":1,"description":"Ordered notional amount. If entered, qty will be null. Can take up to 9 decimal points."},"qty":{"type":"string","minLength":1,"description":"Ordered quantity. If entered, notional will be null. Can take up to 9 decimal points."},"filled_qty":{"type":"string","minLength":1,"description":"Filled quantity"},"filled_avg_price":{"type":"string","description":"Filled average price"},"order_class":{"type":"string","enum":["simple","bracket","oco","oto","mleg",""],"description":"The order classes supported by Alpaca vary based on the order's security type. The following provides a comprehensive breakdown of the supported order classes for each category:\n  - Equity trading: simple (or \"\"), oco, oto, bracket.\n  - Options trading:\n    - simple (or \"\")\n    - mleg (required for multi-leg complex option strategies)\n  - Crypto trading: simple (or \"\").\n\n`simple` `bracket` `oco` `oto` `mleg`","title":"OrderClass","examples":["bracket"]},"order_type":{"type":"string","deprecated":true,"description":"Deprecated in favour of the field \"type\" "},"type":{"type":"string","enum":["market","limit","stop","stop_limit","trailing_stop"],"description":"The order types supported by Alpaca vary based on the order's security type. The following provides a comprehensive breakdown of the supported order types for each category:\n - Equity trading: market, limit, stop, stop_limit, trailing_stop.\n - Options trading: market, limit.\n - Multileg Options trading: market, limit.\n - Crypto trading: market, limit, stop_limit.\n\n`market` `limit` `stop` `stop_limit` `trailing_stop`","title":"OrderType","examples":["market"]},"side":{"type":"string","enum":["buy","sell"],"title":"OrderSide","description":"Represents which side this order was on:\n- buy\n- sell\nRequired for all order classes except for mleg.\n\n`buy` `sell`","examples":["buy"]},"time_in_force":{"type":"string","title":"TimeInForce","description":"The Time-In-Force values supported by Alpaca vary based on the order's security type. Here is a breakdown of the supported TIFs for each specific security type:\n- Equity trading: day, gtc, opg, cls, ioc, fok.\n- Options trading: day.\n- Crypto trading: gtc, ioc.\n\nBelow are the descriptions of each TIF:\n- day:\n  A day order is eligible for execution only on the day it is live. By default, the order is only valid during Regular Trading Hours (9:30am - 4:00pm ET). If unfilled after the closing auction, it is automatically canceled. If submitted after the close, it is queued and submitted the following trading day. However, if marked as eligible for extended hours, the order can also execute during supported extended hours.\n\n- gtc:\n  The order is good until canceled. Non-marketable GTC limit orders are subject to price adjustments to offset corporate actions affecting the issue. We do not currently support Do Not Reduce (DNR) orders to opt out of such price adjustments.\n\n- opg:\n  Use this TIF with a market/limit order type to submit “market on open” (MOO) and “limit on open” (LOO) orders. This order is eligible to execute only in the market opening auction. Any unfilled orders after the open will be cancelled. OPG orders submitted after 9:28am but before 7:00pm ET will be rejected. OPG orders submitted after 7:00pm will be queued and routed to the following day’s opening auction. On open/on close orders are routed to the primary exchange. Such orders do not necessarily execute exactly at 9:30am / 4:00pm ET but execute per the exchange’s auction rules.\n\n- cls:\n  Use this TIF with a market/limit order type to submit “market on close” (MOC) and “limit on close” (LOC) orders. This order is eligible to execute only in the market closing auction. Any unfilled orders after the close will be cancelled. CLS orders submitted after 3:50pm but before 7:00pm ET will be rejected. CLS orders submitted after 7:00pm will be queued and routed to the following day’s closing auction. Only available with API v2.\n\n- ioc:\n  An Immediate Or Cancel (IOC) order requires all or part of the order to be executed immediately. Any unfilled portion of the order is canceled. Only available with API v2. Most market makers who receive IOC orders will attempt to fill the order on a principal basis only, and cancel any unfilled balance. On occasion, this can result in the entire order being cancelled if the market maker does not have any existing inventory of the security in question.\n\n- fok:\n  A Fill or Kill (FOK) order is only executed if the entire order quantity can be filled, otherwise the order is canceled. Only available with API v2.\n\n`day` `gtc` `opg` `cls` `ioc` `fok`","enum":["day","gtc","opg","cls","ioc","fok"],"examples":["day"]},"limit_price":{"type":"string","description":"Limit price"},"stop_price":{"description":"Stop price","type":"string"},"status":{"type":"string","title":"OrderStatus","description":"An order executed through Alpaca can experience several status changes during its lifecycle. The most common statuses are described in detail below:\n\n- new\n  The order has been received by Alpaca, and routed to exchanges for execution. This is the usual initial state of an order.\n\n- partially_filled\n  The order has been partially filled.\n\n- filled\n  The order has been filled, and no further updates will occur for the order.\n\n- done_for_day\n  The order is done executing for the day, and will not receive further updates until the next trading day.\n\n- canceled\n  The order has been canceled, and no further updates will occur for the order. This can be either due to a cancel request by the user, or the order has been canceled by the exchanges due to its time-in-force.\n\n- expired\n  The order has expired, and no further updates will occur for the order.\n\n- replaced\n  The order was replaced by another order, or was updated due to a market event such as corporate action.\n\n- pending_cancel\n  The order is waiting to be canceled.\n\n- pending_replace\n  The order is waiting to be replaced by another order. The order will reject cancel request while in this state.\n\nLess common states are described below. Note that these states only occur on very rare occasions, and most users will likely never see their orders reach these states:\n\n- accepted\n  The order has been received by Alpaca, but hasn’t yet been routed to the execution venue. This could be seen often out side of trading session hours.\n\n- pending_new\n  The order has been received by Alpaca, and routed to the exchanges, but has not yet been accepted for execution. This state only occurs on rare occasions.\n\n- accepted_for_bidding\n  The order has been received by exchanges, and is evaluated for pricing. This state only occurs on rare occasions.\n\n- stopped\n  The order has been stopped, and a trade is guaranteed for the order, usually at a stated price or better, but has not yet occurred. This state only occurs on rare occasions.\n\n- rejected\n  The order has been rejected, and no further updates will occur for the order. This state occurs on rare occasions and may occur based on various conditions decided by the exchanges.\n\n- suspended\n  The order has been suspended, and is not eligible for trading. This state only occurs on rare occasions.\n\n- calculated\n  The order has been completed for the day (either filled or done for day), but remaining settlement calculations are still pending. This state only occurs on rare occasions.\n\n\nAn order may be canceled through the API up until the point it reaches a state of either filled, canceled, or expired.\n\n`new` `partially_filled` `filled` `done_for_day` `canceled` `expired` `replaced` `pending_cancel` `pending_replace` `accepted` `pending_new` `accepted_for_bidding` `stopped` `rejected` `suspended` `calculated`","enum":["new","partially_filled","filled","done_for_day","canceled","expired","replaced","pending_cancel","pending_replace","accepted","pending_new","accepted_for_bidding","stopped","rejected","suspended","calculated"],"examples":["new"]},"extended_hours":{"type":"boolean","description":"If true, eligible for execution outside regular trading hours."},"legs":{"type":"array","description":"When querying non-simple order_class orders in a nested style, an array of Order entities associated with this order. Otherwise, null.","items":{}},"trail_percent":{"type":"string","description":"The percent value away from the high water mark for trailing stop orders."},"trail_price":{"type":"string","description":"The dollar value away from the high water mark for trailing stop orders."},"hwm":{"type":"string","description":"The highest (lowest) market price seen since the trailing stop order was submitted."},"position_intent":{"type":"string","enum":["buy_to_open","buy_to_close","sell_to_open","sell_to_close"],"title":"PositionIntent","description":"Represents the desired position strategy.\n\n`buy_to_open` `buy_to_close` `sell_to_open` `sell_to_close`","examples":["buy_to_open"]}},"required":["symbol","notional","qty","type","side","time_in_force"]}},"trail_percent":{"type":"string","description":"The percent value away from the high water mark for trailing stop orders."},"trail_price":{"type":"string","description":"The dollar value away from the high water mark for trailing stop orders."},"hwm":{"type":"string","description":"The highest (lowest) market price seen since the trailing stop order was submitted."},"position_intent":{"type":"string","enum":["buy_to_open","buy_to_close","sell_to_open","sell_to_close"],"title":"PositionIntent","description":"Represents the desired position strategy.\n\n`buy_to_open` `buy_to_close` `sell_to_open` `sell_to_close`","examples":["buy_to_open"]}},"required":["notional","type","time_in_force"],"$schema":"http://json-schema.org/draft-04/schema#"}}} as const
