const GetTokenizationRequests = {"metadata":{"allOf":[{"type":"object","properties":{"type":{"type":"string","enum":["mint","redeem"],"examples":["mint"],"$schema":"http://json-schema.org/draft-04/schema#","description":"Tokenization request type to be queried"},"status":{"type":"string","enum":["pending","rejected","completed"],"examples":["pending"],"$schema":"http://json-schema.org/draft-04/schema#","description":"Tokenization request status to be queried"},"underlying_symbol":{"type":"string","$schema":"http://json-schema.org/draft-04/schema#","description":"Underlying symbol of the tokenization requests to be queried"},"issuer":{"type":"string","enum":["xstocks"],"examples":["xstocks"],"$schema":"http://json-schema.org/draft-04/schema#","description":"Issuer of the tokenization requests to be queried"},"network":{"type":"string","enum":["solana","arbitrum","ethereum","binance","base","ton","tron","mantle"],"description":"Network of the tokenization requests to be queried","title":"TokenizationNetwork","examples":["solana"],"$schema":"http://json-schema.org/draft-04/schema#"},"after":{"type":"string","format":"date-time","examples":["2025-09-30T18:38:01.942282Z"],"$schema":"http://json-schema.org/draft-04/schema#","description":"The response will include only requests created after this timestamp (exclusive)"},"before":{"type":"string","format":"date-time","examples":["2025-09-30T18:38:01.942282Z"],"$schema":"http://json-schema.org/draft-04/schema#","description":"The response will include only requests created before this timestamp (exclusive)"}},"required":[]}]},"response":{"200":{"type":"array","items":{"title":"TokenizationRequest","type":"object","properties":{"tokenization_request_id":{"type":"string","description":"Unique identifier of the tokenization request set by Alpaca"},"issuer_request_id":{"type":"string","description":"Unique identifier of the tokenization request set by the issuer"},"account":{"type":"string","description":"Alpaca account ID associated with this tokenization request"},"issuer_account":{"type":"string","description":"Issuer's account ID associated with this tokenization request"},"created_at":{"type":"string","format":"date-time"},"updated_at":{"type":"string","format":"date-time"},"type":{"type":"string","enum":["mint","redeem"],"description":"Tokenization request type\n\n`mint` `redeem`","title":"TokenizationRequestType","examples":["mint"]},"status":{"type":"string","enum":["pending","rejected","completed"],"description":"Status of the tokenization request\n\n`pending` `rejected` `completed`","title":"TokenizationRequestStatus","examples":["completed"]},"underlying_symbol":{"type":"string","description":"The underlying asset symbol"},"token_symbol":{"type":"string","description":"The tokenized asset symbol"},"qty":{"type":"string","description":"The quantity to convert for this tokenization request. It can be fractional."},"issuer":{"type":"string","enum":["xstocks","st0x"],"description":"The tokenized asset's issuer\n\n`xstocks` `st0x`","title":"TokenizationIssuer","examples":["xstocks"]},"network":{"type":"string","enum":["solana","arbitrum","ethereum","binance","base","ton","tron","mantle"],"description":"The token's blockchain network\n\n`solana` `arbitrum` `ethereum` `binance` `base` `ton` `tron` `mantle`","title":"TokenizationNetwork","examples":["solana"]},"wallet_address":{"type":"string","description":"The wallet address associated with this tokenization request"},"tx_hash":{"type":"string","description":"Transaction hash of the completed request on the blockchain"},"fees":{"type":"string","description":"Fees charged for this tokenization request"}},"required":["tokenization_request_id","created_at","type","status","underlying_symbol","token_symbol","qty","issuer","network","wallet_address"]},"$schema":"http://json-schema.org/draft-04/schema#"},"401":{"title":"Error","type":"object","properties":{"code":{"type":"number"},"message":{"type":"string"}},"required":["code","message"],"$schema":"http://json-schema.org/draft-04/schema#"},"403":{"title":"Error","type":"object","properties":{"code":{"type":"number"},"message":{"type":"string"}},"required":["code","message"],"$schema":"http://json-schema.org/draft-04/schema#"},"422":{"title":"Error","type":"object","properties":{"code":{"type":"number"},"message":{"type":"string"}},"required":["code","message"],"$schema":"http://json-schema.org/draft-04/schema#"}}} as const
